// /frontend/src/components/Radar.jsx
import React, { useEffect, useMemo, useRef, useState } from "react";
import { MapContainer, TileLayer } from "react-leaflet";
import "leaflet/dist/leaflet.css";

export default function Radar({
  center = [33.7490, -84.3880], // fallback: Atlanta
  zoom = 5,
  height = 260,
  className = ""
}) {
  const [frameTime, setFrameTime] = useState(null);
  const alive = useRef(true);

  // Ensure we always have a valid center
  const safeCenter = useMemo(() => {
    const ok =
      Array.isArray(center) &&
      center.length === 2 &&
      center.every((n) => typeof n === "number" && isFinite(n));
    return ok ? center : [33.7490, -84.3880];
  }, [center]);

  // Grab latest RainViewer time (very cheap request). If it fails, use a rounded "now".
  useEffect(() => {
    alive.current = true;
    (async () => {
      try {
        const res = await fetch("https://api.rainviewer.com/public/weather-maps.json");
        const data = await res.json();
        const latest =
          data?.radar?.past?.at(-1)?.time ?? data?.radar?.nowcast?.[0]?.time ?? null;
        if (alive.current && latest) setFrameTime(latest);
      } catch {
        // ignore; fallback below
      }
    })();
    return () => {
      alive.current = false;
    };
  }, []);

  const effectiveTime = useMemo(() => {
    if (frameTime) return frameTime;
    // fallback: nearest 10-min timestamp (seconds)
    return Math.floor(Date.now() / (10 * 60 * 1000)) * (10 * 60);
  }, [frameTime]);

  // Minimal single tile layer: reflectivity with snow overlay, no base map
  const radarUrl = useMemo(() => {
    // format: /v2/radar/{time}/256/{z}/{x}/{y}/2/1_1.png  (smooth=1, snow=1)
    return `https://tilecache.rainviewer.com/v2/radar/${effectiveTime}/256/{z}/{x}/{y}/2/1_1.png`;
  }, [effectiveTime]);

  // Render nothing until we have a safe center (prevents "Set map center and zoom first")
  if (!safeCenter) return null;

  return (
    <div className={`w-full ${className}`} style={{ height }}>
      <MapContainer
        center={safeCenter}
        zoom={zoom}
        style={{ width: "100%", height: "100%", borderRadius: 16, overflow: "hidden" }}
        // turn off *everything* interactive/heavy
        scrollWheelZoom={false}
        dragging={false}
        boxZoom={false}
        doubleClickZoom={false}
        keyboard={false}
        zoomControl={false}
        attributionControl={false}
        zoomAnimation={false}
        fadeAnimation={false}
        markerZoomAnimation={false}
        inertia={false}
        preferCanvas={true}
      >
        <TileLayer
          url={radarUrl}
          opacity={0.9}
          updateWhenIdle={true}
          updateWhenZooming={false}
          keepBuffer={2}
          detectRetina={false}
        />
      </MapContainer>
    </div>
  );
}
